code.Python3:
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        r = int(data[i])
        if r >= 2000:
            out.append('1')
        elif r >= 1600:
            out.append('2')
        else:
            out.append('3')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

